class Codec:
    def __init__(self):
        self.store = {}
        self.counter = 0

    def encode(self, longUrl: str) -> str:
        self.counter += 1
        code = 'https://tiny.url/' + str(self.counter)
        self.store[code] = longUrl
        return code

    def decode(self, shortUrl: str) -> str:
        return self.store[shortUrl]

